ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?position ?company ?recruitment_agency WHERE {
  ?positions a :Position .
  ?positions p:position ?position .
  ?positions p:company ?company .
  ?positions p:recruitment_agency ?recruitment_agency .
} }
  component: { SELECT ?position ?recruitment_agency WHERE {
  ?positions a :Position .
  ?positions p:position ?position .
  ?positions p:recruitment_agency ?recruitment_agency .
} }
  component_2: { SELECT ?position ?company WHERE {
  ?positions a :Position .
  ?positions p:position ?position .
  ?positions p:company ?company .
} }
}

PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?company ?recruitment_agency WHERE {
  ?positions a :Position .
  ?positions p:company ?company .
  ?positions p:recruitment_agency ?recruitment_agency .
  ?positions p:position ?position_f .
  FILTER(STR(?position_f) = "Software Engineer")
} }
  component: { SELECT ?recruitment_agency WHERE {
  ?positions a :Position .
  ?positions p:recruitment_agency ?recruitment_agency .
  ?positions p:position ?position_f .
  FILTER(STR(?position_f) = "Software Engineer")
} }
  component_2: { SELECT ?company WHERE {
  ?positions a :Position .
  ?positions p:company ?company .
  ?positions p:position ?position_f .
  FILTER(STR(?position_f) = "Software Engineer")
} }
}
